1	import { mkdir, readFile, appendFile, writeFile } from "node:fs/promises";
2	import { existsSync, readFileSync, readdirSync } from "node:fs";
3	import path from "node:path";
4	import { config, resolveBridgeConfigPath } from "./config.js";
5	import { classifyFact, topicKeywordHint } from "./topic-rules.js";
6	import { STICKER_EMOTIONS } from "./stickerMap.js";
7	import {
8	  appendFactShardOnly,
9	  listTopicShards,
10	  formatFactLine,
11	} from "./facts-store.js";
12	import { compressFactsForPreamble } from "./local-llm.js";
13	import { listPendingIngests } from "./artifact.js";
14	
15	function factsPath(userId: number): string {
16	  return path.join(config.memoryDir, `facts-${userId}.md`);
17	}
18	
19	export async function loadFacts(userId: number): Promise<string> {
20	  try {
21	    return (await readFile(factsPath(userId), "utf8")).trim();
22	  } catch {
23	    return "";
24	  }
25	}
26	
27	export async function appendFact(userId: number, line: string): Promise<void> {
28	  await mkdir(config.memoryDir, { recursive: true });
29	  const text = line.trim();
30	  const formatted = formatFactLine(text);
31	  // Guard: if the existing file doesn't end with a newline, prepend one so
32	  // we never glue two facts together on the same line.
33	  let prefix = "";
34	  try {
35	    const existing = await readFile(factsPath(userId), "utf8");
36	    if (existing.length > 0 && !existing.endsWith("\n")) prefix = "\n";
37	  } catch {
38	    /* file doesn't exist yet — nothing to guard */
39	  }
40	  await appendFile(factsPath(userId), prefix + formatted, "utf8");
41	  // Mirror to per-topic shard. Failures here are warned but not rethrown
42	  // because the master log is authoritative.
43	  appendFactShardOnly({
44	    userId,
45	    formattedLine: formatted,
46	    rawText: text,
47	  });
48	}
49	
50	/** Strip leading "- [f_xxxxxx] [timestamp] " or "- [timestamp] " bullet. */
51	function stripFactPrefix(line: string): string {
52	  return line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "").trim();
53	}
54	
55	/** List existing facts as plain strings (timestamp/bullet stripped). */
56	export async function listFacts(userId: number): Promise<string[]> {
57	  const raw = await loadFacts(userId);
58	  if (!raw) return [];
59	  return raw
60	    .split(/\r?\n/)
61	    .map(stripFactPrefix)
62	    .filter((s) => s.length > 0);
63	}
64	
65	/**
66	 * Append facts, skipping ones that duplicate existing lines. Comparison is
67	 * per-line after normalising (strip bullet/timestamp, lowercase, collapse
68	 * whitespace) — avoids the earlier substring-match footgun where any new
69	 * fact sharing a phrase with an older one was silently dropped.
70	 */
71	export async function appendFactsDedup(userId: number, lines: string[]): Promise<number> {
72	  const norm = (s: string) => stripFactPrefix(s).toLowerCase().replace(/\s+/g, " ").trim();
73	  const existing = new Set((await listFacts(userId)).map(norm));
74	  let added = 0;
75	  for (const raw of lines) {
76	    const line = stripFactPrefix(raw);
77	    if (!line) continue;
78	    const key = norm(line);
79	    if (existing.has(key)) continue;
80	    await appendFact(userId, line);
81	    existing.add(key);
82	    added++;
83	  }
84	  return added;
85	}
86	
87	// Topic classification rules live in ./topic-rules.ts so mcp-memory can
88	// share the same list and expand topic-name queries into keyword OR match.
89	
90	interface MemoryBlockOptions {
91	  tail: number; // 0 = inject everything
92	  topics: boolean;
93	  userId?: number; // used to read shard directory for the topic index
94	  /** Pre-compressed recent facts (from local LLM). If set, replaces raw recent lines. */
95	  compressed?: string | null;
96	}
97	
98	function buildMemoryBlock(facts: string, opts: MemoryBlockOptions): string {
99	  if (!facts) return "";
100	  const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
101	  const total = lines.length;
102	
103	  // tail=0 → preserve old behaviour (inject everything, no index).
104	  if (opts.tail === 0 || total <= opts.tail) {
105	    return (
106	      "[Long-term memory about this user — use when relevant, don't mention unless asked]\n" +
107	      lines.join("\n") +
108	      "\n[End memory]\n\n"
109	    );
110	  }
111	
112	  const recent = lines.slice(-opts.tail);
113	  const older = lines.slice(0, -opts.tail);
114	
115	  // Split recent facts into two tracks: user preferences vs agent notes.
116	  const userPrefLines: string[] = [];
117	  const agentNoteLines: string[] = [];
118	  for (const line of recent) {
119	    const raw = line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "");
120	    const topic = classifyFact(raw);
121	    if (topic === "user-preference") {
122	      userPrefLines.push(line);
123	    } else {
124	      agentNoteLines.push(line);
125	    }
126	  }
127	
128	  let recentContent: string;
129	  if (opts.compressed) {
130	    // Compressed mode doesn't split (LLM already summarized)
131	    recentContent = opts.compressed;
132	  } else if (userPrefLines.length > 0) {
133	    recentContent =
134	      "## About this user\n" +
135	      userPrefLines.join("\n") +
136	      "\n## Agent notes\n" +
137	      agentNoteLines.join("\n");
138	  } else {
139	    recentContent = recent.join("\n");
140	  }
141	
142	  let block =
143	    `[Long-term memory about this user — recent ${recent.length} of ${total} facts, use when relevant]\n` +
144	    recentContent +
145	    "\n[End memory]\n\n";
146	
147	  if (opts.topics && older.length > 0) {
148	    // Preferred path: list the user's shard directory and use each
149	    // file's line count as the topic count. This lets the preamble
150	    // survive topic rule changes (files reflect what's actually on
151	    // disk). Falls back to classify-on-the-fly if the shard dir
152	    // doesn't exist yet (fresh install, pre-rebuild, etc.).
153	    let indexRows: Array<[string, number]> = [];
154	    let source: "shard" | "classify" = "classify";
155	    if (opts.userId !== undefined) {
156	      const shards = listTopicShards(opts.userId);
157	      if (shards.length > 0) {
158	        source = "shard";
159	        indexRows = shards.map((s) => [s.topic, s.count] as [string, number]);
160	      }
161	    }
162	    if (source === "classify") {
163	      const counts = new Map<string, number>();
164	      for (const line of older) {
165	        const raw = line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "");
166	        const topic = classifyFact(raw);
167	        counts.set(topic, (counts.get(topic) ?? 0) + 1);
168	      }
169	      indexRows = Array.from(counts.entries()).sort((a, b) => b[1] - a[1]);
170	    }
171	
172	    const indexLines = indexRows
173	      .map(([t, n]) => {
174	        const hint = topicKeywordHint(t, 3);
175	        return hint ? `- ${t} (${n}): ${hint}` : `- ${t} (${n})`;
176	      })
177	      .join("\n");
178	
179	    const headerNote =
180	      source === "shard"
181	        ? `${older.length} older facts (plus any newer ones), sharded at facts_Topic/${opts.userId}/`
182	        : `${older.length} older facts grouped by topic`;
183	
184	    block +=
185	      `[Memory topics — ${headerNote}]\n` +
186	      indexLines +
187	      "\n\n" +
188	      "If the user asks about a topic above and the recent facts don't cover it,\n" +
189	      "call the `list_facts` MCP tool with the topic name — the server reads\n" +
190	      "that shard file directly, e.g. `list_facts({ query: \"bridge-token\" })`.\n" +
191	      "Use query=\"\" and tail=0 only if you genuinely need the full set.\n" +
192	      "[End topics]\n\n";
193	  }
194	
195	  // 七項行為紀律的壓縮版（原本各自獨立成塊，約 3.4k chars；壓成單塊保留
196	  // 每條的觸發條件 + 動作，省約一半 preamble 固定成本）。
197	  block +=
198	    "[Agent disciplines]\n" +
199	    "MEMORY — store: preferences, decisions, architecture/env choices, reusable lessons, tool configs, naming rules.\n" +
200	    "Skip: one-time confirmations, transient status, session-only facts, anything in code/commits or re-derivable in <30s.\n" +
201	    "Test: useless in a new session 2 weeks later → don't store. Significant decisions keep the WHY:\n" +
202	    "「因為 X 所以選 Y（排除 Z 因為 W）」/ \"Chose Y because X (rejected Z because W)\".\n" +
203	    "REFLEXION — same approach fails ≥2 times (tool error, no-match edit, failing build) → STOP, diagnose in 1-2\n" +
204	    "sentences, switch to a fundamentally different approach (different tool/strategy, or ask user). Never retry a 3rd time.\n" +
205	    "CONTEXT BUDGET — research-heavy task needing >2 web_fetch or >10 tool calls → delegate to researcher or go concise.\n" +
206	    "Prefer snippets/summaries over full fetches. On ⚠️ CONTEXT BUDGET WARNING: stop research, produce output now.\n" +
207	    "Reports: gather conclusions first (≤3 searches), then write the file in ONE call.\n" +
208	    "ASK BUTTONS — presenting 2+ alternatives, yes/no confirmation, or 「要不要做 X？」→ MUST append <<ASK:...>>.\n" +
209	    "Self-check triggers: 「哪個」「要選」「方案A/B」「which」「prefer」. Options listed without ASK → add the token before finishing.\n" +
210	    "MEMORY HONESTY — memory-based answers: say where you found it (topic shard / wiki page); facts >60 days old\n" +
211	    "→ 「此資訊可能已過時」; absence of records → 「記憶中沒有相關記錄」, never assert non-existence.\n" +
212	    "Applies only to brain questions (people/decisions/history/preferences), not code or general knowledge.\n" +
213	    "CAPABILITY GAPS — clumsy pattern recurs ≥2 times → write+test a script in scripts/, then confirm via <<ASK:...>>\n" +
214	    "before adopting (declined → delete); broader patterns → <<SKILL_PROPOSE:name|reason>>. Check [Available scripts]\n" +
215	    "first. Never silently add tools; never propose for one-offs.\n" +
216	    "[End agent disciplines]\n\n";
217	
218	  return block;
219	}
220	
221	/**
222	 * Char-length breakdown of the preamble by section. Useful for the
223	 * bridge's context-usage UI so the user can see where the tokens go
224	 * (tool notes / env / memory) without having to inspect the raw string.
225	 *
226	 * All counts are raw character lengths; convert to tokens via the same
227	 * ~chars/4 heuristic used elsewhere (`estimateTokens`).
228	 */
229	export interface PreambleBreakdown {
230	  /** Full preamble text (same as the string returned by buildPreamble). */
231	  text: string;
232	  /** Total chars (= text.length). Convenience so callers don't re-measure. */
233	  total: number;
234	  /** sendFileNote + askNote + scheduleNote combined. */
235	  toolNotes: number;
236	  /** Environment block (MEMORY_DIR / SKILL_DIR / AGENT_CONFIG_DIR / USER_ID). */
237	  envBlock: number;
238	  /** Long-term memory block (recent facts + topic index). 0 if no facts. */
239	  memoryBlock: number;
240	  /** Daily log block (most recent dailylog). 0 if none. */
241	  dailylogBlock: number;
242	  /** Wiki index block (page titles from wiki/index.md). 0 if no wiki. */
243	  wikiBlock: number;
244	  /** Document tree indexes listing. 0 if no indexes. */
245	  indexBlock: number;
246	  /** Available agent-developed scripts (tool-* in scripts/). 0 if none. */
247	  scriptsBlock: number;
248	  /** User profile block (structured user identity/preferences). 0 if none. */
249	  userProfileBlock: number;
250	  /** Stripped tail facts included in preamble — for dedup in memory-recall. */
251	  tailFacts: Set<string>;
252	}
253	
254	
255	
256	/**
257	 * Like buildPreamble but also returns per-section char lengths so the
258	 * bridge can display where context tokens are going. Prefer this in
259	 * new code; buildPreamble is kept for callers that only want the text.
260	 */
261	export function buildPreambleWithBreakdown(
262	  facts: string,
263	  userId?: number,
264	  opts?: { tailOverride?: number; compressed?: string | null }
265	): PreambleBreakdown {
266	  const {
267	    sendFileNote,
268	    askNote,
269	    scheduleNote,
270	    skillUsedNote,
271	    goalDoneNote,
272	    restartNote,
273	    stickerNote,
274	    wikiQueryNote,
275	    skillProposeNote,
276	    continueNote,
277	    relayDelegateNote,
278	    specialistProxyNote,
279	    parallelDelegateNote,
280	    rtkNote,
281	    envBlock,
282	    memoryBlock,
283	    dailylogBlock,
284	    wikiBlock,
285	    indexBlock,
286	    scriptsBlock,
287	    userProfileBlock,
288	  } = buildPreambleSections(facts, userId, opts?.tailOverride, opts?.compressed);
289	  const text =
290	    sendFileNote +
291	    askNote +
292	    scheduleNote +
293	    skillUsedNote +
294	    goalDoneNote +
295	    restartNote +
296	    stickerNote +
297	    wikiQueryNote +
298	    skillProposeNote +
299	    continueNote +
300	    relayDelegateNote +
301	    specialistProxyNote +
302	    parallelDelegateNote +
303	    rtkNote +
304	    envBlock +
305	    userProfileBlock +
306	    memoryBlock +
307	    dailylogBlock +
308	    wikiBlock +
309	    indexBlock +
310	    scriptsBlock;
311	  // Build a Set of stripped tail facts for dedup in memory-recall.
312	  const tailCount = opts?.tailOverride ?? config.memoryPreambleTail;
313	  const tailFacts = new Set<string>();
314	  if (facts) {
315	    const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
316	    const recent = lines.slice(-tailCount);
317	    for (const line of recent) {
318	      tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
319	    }
320	  }
321	
322	  return {
323	    text,
324	    total: text.length,
325	    toolNotes:
326	      sendFileNote.length +
327	      askNote.length +
328	      scheduleNote.length +
329	      skillUsedNote.length +
330	      goalDoneNote.length +
331	      restartNote.length +
332	      stickerNote.length +
333	      wikiQueryNote.length +
334	      skillProposeNote.length +
335	      continueNote.length +
336	      relayDelegateNote.length +
337	      specialistProxyNote.length,
338	    envBlock: envBlock.length,
339	    memoryBlock: memoryBlock.length,
340	    dailylogBlock: dailylogBlock.length,
341	    wikiBlock: wikiBlock.length,
342	    indexBlock: indexBlock.length,
343	    scriptsBlock: scriptsBlock.length,
344	    userProfileBlock: userProfileBlock.length,
345	    tailFacts,
346	  };
347	}
348	
349	export function buildPreamble(facts: string, userId?: number): string {
350	  return buildPreambleWithBreakdown(facts, userId).text;
351	}
352	
353	/**
354	 * Minimal preamble for local models (Ollama). Keeps total under ~2000 tokens
355	 * so small models don't choke on an oversized system prompt.
356	 * Includes: identity, recent facts, memory tool hints.
357	 */
358	export function buildLocalPreamble(facts: string, userId?: number): PreambleBreakdown {
359	  const lines = facts ? facts.split(/\r?\n/).filter((l) => l.trim().length > 0) : [];
360	  const tail = Math.min(5, lines.length);
361	  const recent = lines.slice(-tail);
362	  const recentContent = recent.map((l) => l.trim()).join("\n");
363	
364	  const toolGuide =
365	    "[MCP Tools — call these via tool_call]\n" +
366	    "• remember({ text }) — store a fact to long-term memory. Use for user preferences, decisions, lessons.\n" +
367	    "• list_facts({ query, tail? }) — retrieve facts. query=topic name or substring. tail caps results (default 20).\n" +
368	    "• forget({ query, confirm? }) — delete facts by substring match. First call previews; second call with confirm token deletes.\n" +
369	    "Rules: one fact per remember call; short self-contained sentences; skip trivial/transient info.\n" +
370	    "[End tools]\n\n";
371	
372	  let text =
373	    "You are a helpful AI assistant. Respond in the user's language. Be concise.\n" +
374	    toolGuide;
375	
376	  if (recentContent) {
377	    text += `[Recent memory — ${tail} of ${lines.length} facts]\n${recentContent}\n[End memory]\n\n`;
378	  }
379	
380	  const tailFacts = new Set<string>();
381	  for (const line of recent) {
382	    tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
383	  }
384	
385	  return {
386	    text,
387	    total: text.length,
388	    toolNotes: toolGuide.length,
389	    envBlock: 0,
390	    memoryBlock: recentContent.length,
391	    dailylogBlock: 0,
392	    wikiBlock: 0,
393	    indexBlock: 0,
394	    scriptsBlock: 0,
395	    userProfileBlock: 0,
396	    tailFacts,
397	  };
398	}
399	
400	/**
401	 * Internal: builds each section of the preamble separately so
402	 * buildPreambleWithBreakdown can measure them. Ordering matches what
403	 * buildPreamble concatenates.
404	 */
405	function buildPreambleSections(
406	  facts: string,
407	  userId?: number,
408	  tailOverride?: number,
409	  compressed?: string | null,
410	): {
411	  sendFileNote: string;
412	  askNote: string;
413	  scheduleNote: string;
414	  skillUsedNote: string;
415	  goalDoneNote: string;
416	  restartNote: string;
417	  stickerNote: string;
418	  wikiQueryNote: string;
419	  skillProposeNote: string;
420	  continueNote: string;
421	  relayDelegateNote: string;
422	  specialistProxyNote: string;
423	  parallelDelegateNote: string;
424	  rtkNote: string;
425	  envBlock: string;
426	  memoryBlock: string;
427	  dailylogBlock: string;
428	  wikiBlock: string;
429	  indexBlock: string;
430	  scriptsBlock: string;
431	  userProfileBlock: string;
432	} {
433	  const sendFileNote =
434	    "[Telegram bridge tool: send file]\n" +
435	    "`<<SEND_FILE:絕對路徑>>` — 附檔給使用者（圖片≤10MB走photo，餘走document）。路徑須在 TG_SEND_ROOTS 底下。\n" +
436	    "僅在使用者明確要求傳檔時加；產生/儲存檔案不構成傳檔意圖，回報路徑即可。\n" +
437	    "[End tool]\n\n";
438	  const askNote =
439	    "[Telegram bridge tool: ask with buttons]\n" +
440	    "`<<ASK:id|key=label|*key=label|...>>`（單行）— 渲染 inline keyboard，點擊回送 `[ASK:id] key`。\n" +
441	    "限制：id≤32 key≤20 [a-zA-Z0-9_-]；label≤40 不含`|``=`；1-8選項；`*`標推薦（至多一個）。\n" +
442	    "選項說明長時正文列 1./2./3.，label 只放短標題。違反限制會原封顯示無法渲染。\n" +
443	    "[End tool]\n\n";
444	  const scheduleNote =
445	    "[Telegram bridge tool: schedule]\n" +
446	    "`<<SCHEDULE:<time>|<prompt>>>`（單行）— 建立延遲/常態性排程。\n" +
447	    "一次性：`30s`/`15m`/`2h`/`1d`/`HH:MM`/`tomorrow HH:MM`/`MM-DD HH:MM`/`YYYY-MM-DD HH:MM`。\n" +
448	    "常態性：`every 30m`/`daily 09:00`/`weekly mon 09:00`/`cron */5 * * * *`。\n" +
449	    "prompt≤1000字，不可含`>>`。單則至多3個。僅在使用者明確要求排程時使用。\n" +
450	    "[End tool]\n\n";
451	  const skillUsedNote =
452	    "[Telegram bridge tool: report skill use]\n" +
453	    "`<<SKILL_USED:skill-name|reason>>`（單行）— 你參考了某 SKILL.md 時加。\n" +
454	    "name=資料夾名 kebab-case≤60；reason≤500 不含`|`或換行。一則至多5個，重複去重。\n" +
455	    "[End tool]\n\n";
456	  const goalDoneNote =
457	    "[Telegram bridge tool: goal done signal]\n" +
458	    "`<<GOAL_DONE:reason>>`（單行）— /goal 標的達成時加在回覆最後。\n" +
459	    "reason≤500 不含`|`或換行。未完成不加。/goal 未啟動時忽略。\n" +
460	    "[End tool]\n\n";
461	  const restartNote =
462	    "[Telegram bridge tool: restart]\n" +
463	    "`<<RESTART:reason>>`（單行）— 重啟 session（context 過大、工具異常、需刷新 preamble）。\n" +
464	    "重要：restart 前先 remember() 存工作狀態，格式：\n" +
465	    "  - `[WS] task: <目標>` — 當前高層任務\n" +
466	    "  - `[WS] completed: <已完成項>` — 本 session 完成的事（可多條）\n" +
467	    "  - `[WS] blocked: <阻塞項>` — 等待中的事\n" +
468	    "  - `[WS] key_refs: <重要路徑或值>` — 需帶到下個 session 的參考\n" +
469	    "  - `[WS] next_action: <下一步>` — 恢復後第一件要做的事\n" +
470	    "Guardrail：同 /goal 最多5次，間隔≥5分鐘。\n" +
471	    "[End tool]\n\n";
472	  const stickerNote =
473	    "[Telegram bridge tool: sticker]\n" +
474	    "`<<STICKER:emotion>>`（單行）— 發送 video sticker。\n" +
475	    `可用：${STICKER_EMOTIONS.join(", ")}。適時使用（打招呼/完成/道歉等），不要每則都加。\n` +
476	    "[End tool]\n\n";
477	  const wikiQueryNote =
478	    "[Telegram bridge tool: wiki query]\n" +
479	    "`<<WIKI_QUERY:slug|summary>>`（單行）— 標記此回覆值得存為 wiki page。\n" +
480	    "slug=[a-z0-9_-]≤80；summary≤200字描述主題。Bridge 會自動整理成 wiki/queries/ 頁面。\n" +
481	    "條件：回覆≥200字 + 跨3+不同主題的綜合性回答。短回覆/操作確認不加。\n" +
482	    "[End tool]\n\n";
483	  const skillProposeNote =
484	    "[Telegram bridge tool: propose skill]\n" +
485	    "`<<SKILL_PROPOSE:name|reason>>`（單行）— 提議把本次對話模式寫成 skill。\n" +
486	    "name=kebab-case≤60（將成為 ms-{name}/ 資料夾名）；reason≤500 說明為何值得。\n" +
487	    "Bridge 發確認按鈕，使用者同意才萃取。僅在發現可跨專案重用的模式時加，一則至多1個。\n" +
488	    "[End tool]\n\n";
489	  const continueNote =
490	    "[Telegram bridge tool: continue]\n" +
491	    "`<<CONTINUE>>`（單行）— 告訴 bridge 你還沒做完，需要再一輪。\n" +
492	    "Bridge 收到後自動排程下一個 turn，不需使用者介入。\n" +
493	    "使用時機：單次回覆做不完（tool call 太多、要改多個檔案、多步驟任務）。\n" +
494	    "限制：/goal 啟動時不需要用（goal 系統自帶 continuation）；一則只認一個。\n" +
495	    "[End tool]\n\n";
496	  const relayDelegateNote = config.relay
497	    ? buildRelayDelegateNote()
498	    : "";
499	  const specialistProxyNote = buildSpecialistProxyNote();
500	  const parallelDelegateNote = buildParallelDelegateNote();
501	  const memoryBlock = buildMemoryBlock(facts, {
502	    tail: tailOverride ?? config.memoryPreambleTail,
503	    topics: config.memoryPreambleTopics,
504	    userId,
505	    compressed,
506	  });
507	  const dailylogBlock = buildDailylogBlock();
508	  const wikiBlock = buildWikiIndexBlock();
509	  const indexBlock = buildIndexBlock();
510	  const envBlock = buildEnvironmentBlock(userId);
511	  const scriptsBlock = buildScriptsBlock();
512	  const userProfileBlock = buildUserProfileBlock();
513	  const rtkNote = config.rtkShellRewrite
514	    ? "[Shell optimization: RTK]\n" +
515	      "rtk (Rust Token Killer) is installed. When using the shell tool, prefix commands with `rtk` for compressed output:\n" +
516	      "  `rtk git status` / `rtk git diff` / `rtk git log` — compact git output\n" +
517	      "  `rtk read <file>` / `rtk read <file> -l aggressive` — signatures only\n" +
518	      "  `rtk grep <pattern> .` — grouped search results\n" +
519	      "  `rtk cargo test` / `rtk npm test` — failures only\n" +
520	      "Do NOT prefix: interactive commands, piped chains, or commands where full output is needed.\n" +
521	      "[End RTK]\n\n"
522	    : "";
523	  return {
524	    sendFileNote,
525	    askNote,
526	    scheduleNote,
527	    skillUsedNote,
528	    goalDoneNote,
529	    restartNote,
530	    stickerNote,
531	    wikiQueryNote,
532	    skillProposeNote,
533	    continueNote,
534	    relayDelegateNote,
535	    specialistProxyNote,
536	    parallelDelegateNote,
537	    rtkNote,
538	    envBlock,
539	    memoryBlock,
540	    dailylogBlock,
541	    wikiBlock,
542	    indexBlock,
543	    scriptsBlock,
544	    userProfileBlock,
545	  };
546	}
