548	/**
549	 * Environment preamble: tells the agent where this bridge stores memory,
550	 * skills, agent config files, and which Telegram user owns the session.
551	 * Skills and long-term notes can reference these as ${MEMORY_DIR},
552	 * ${SKILL_DIR}, ${AGENT_CONFIG_DIR}, ${USER_ID} rather than hard-coding
553	 * machine-specific paths — so the same SKILL.md works on the Kiro box,
554	 * the Codex box, and the Claude box.
555	 *
556	 * Heuristic: agent.command name hints which CLI we're paired with
557	 * (kiro → ~/.kiro, codex → ~/.codex, claude → ~/.claude). Any of the
558	 * three variables can be overridden via the matching env var.
559	 */
560	/**
561	 * Build relay delegate tool note from external config file.
562	 * Reads MEMORY_DIR/config/relay-peers.json (fallback: AGENT_CONFIG_DIR).
563	 */
564	function buildRelayDelegateNote(): string {
565	  interface PeerConfig {
566	    abilities: string[];
567	    delegateWhen: string[];
568	  }
569	  const cfgPath = resolveBridgeConfigPath("relay-peers.json", detectAgentConfigDir());
570	  let peers: Record<string, PeerConfig>;
571	  try {
572	    peers = JSON.parse(readFileSync(cfgPath, "utf8"));
573	  } catch {
574	    console.warn(`[preamble] relay-peers.json not found at ${cfgPath} — relay delegate tool note disabled`);
575	    return "";
576	  }
577	  const names = Object.keys(peers);
578	  if (names.length === 0) return "";
579	  let note = "[Telegram bridge tool: relay delegate]\n";
580	  note += "`<<RELAY_DELEGATE:<peer>|goal prompt>>`（單行）— 委派任務給另一台機器上的 AI agent。\n";
581	  note += "也接受 JSON 格式：`<<RELAY_DELEGATE:<peer>|{\"id\":\"<id>\",\"goal\":\"...\",\"context\":\"...\"}>>`\n";
582	  note += "純文字時 bridge 自動產生 id。goal prompt 不可含 `>>` 或 `|`。\n";
583	  note += "Bridge 會自動保存你的工作狀態，對方完成後結果靜默注入你的 session。\n\n";
584	  for (const [name, cfg] of Object.entries(peers)) {
585	    const extra = (cfg as any).note ? `（${(cfg as any).note}）` : "";
586	    note += `「${name}」${extra}的能力：\n`;
587	    for (const a of cfg.abilities) note += `- ${a}\n`;
588	    note += `\n何時委派給「${name}」：\n`;
589	    for (const w of cfg.delegateWhen) note += `- ${w}\n`;
590	    note += "\n";
591	  }
592	  note += "格式規則：\n";
593	  note += "- 純文字格式（推薦）：`<<RELAY_DELEGATE:peer|任務描述>>`\n";
594	  note += "- JSON 格式（需要帶 context/maxTurns 時）：`<<RELAY_DELEGATE:peer|{\"id\":\"rd_xxx\",\"goal\":\"...\",\"context\":\"...\"}>>` \n";
595	  note += "- goal/prompt 不可含 `>>` 或 `|`\n";
596	  note += "- 不要等結果——發出後正常回覆使用者「已委派」即可\n";
597	  note += "- ⚠️ 重要：發 RELAY_DELEGATE 的 turn 必須包含至少一個 tool call（如 list_facts），否則 token 會被 CLI 吞掉不送出\n";
598	  note += "[End tool]\n\n";
599	  return note;
600	}
