602	function buildSpecialistProxyNote(): string {
603	  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
604	  let specs: { name: string; cwd: string }[];
605	  try {
606	    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
607	  } catch {
608	    return "";
609	  }
610	  if (!Array.isArray(specs) || specs.length === 0) return "";
611	  let note = "[Telegram bridge tool: specialist proxy]\n";
612	  note += "`<<SPECIALIST_PROXY:name|使用者的原始訊息>>`（單行）— 把使用者的訊息轉交給本機 specialist 即時回答。\n";
613	  note += "進入 proxy 模式後，使用者後續訊息直送 specialist，回覆直送使用者，直到使用者說 /back。\n";
614	  note += "Specialist 的記憶會回流到你的 facts。proxy 結束時你會收到對話摘要。\n\n";
615	  note += "可用 specialist：\n";
616	  for (const s of specs) {
617	    note += `- ${s.name}（工作目錄：${s.cwd}）\n`;
618	  }
619	  note += "\n使用時機：使用者的問題明確屬於某 specialist 的領域，且需要即時互動（不是背景任務）。\n";
620	  note += "背景任務用 RELAY_DELEGATE；即時對話用 SPECIALIST_PROXY。\n";
621	  note += "[End tool]\n\n";
