623	}
624	
625	function buildParallelDelegateNote(): string {
626	  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
627	  let specs: { name: string }[];
628	  try {
629	    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
630	  } catch {
631	    return "";
632	  }
633	  if (!Array.isArray(specs) || specs.length === 0) return "";
634	  let note = "[Telegram bridge tool: parallel delegate]\n";
635	  note += "`<<PARALLEL_DELEGATE:task_id|specialist_name|goal prompt>>`（單行）— 並行委派多個任務給 specialist。\n";
636	  note += "同一個 turn 放多個 PARALLEL_DELEGATE，bridge 會同時 spawn 多個獨立 instance 並行執行。\n";
637	  note += "全部完成後結果一次注入你的 session（格式：[PARALLEL_RESULT:task_id]）。\n\n";
638	  note += "格式規則：\n";
639	  note += "- task_id：唯一識別碼（如 `pt_1`、`pt_2`）\n";
640	  note += "- specialist_name：目標 specialist（同一個 name 可以開多個 instance）\n";
641	  note += "- goal prompt：任務描述（不可含 `>>` 或 `|`）\n";
642	  note += "- 每個 task 獨立 instance，互不干擾——但要避免多個 task 改同一個檔案\n";
643	  note += "- ⚠️ 同樣需要至少一個 tool call 防止 CLI 吞 token\n\n";
