708	          `- ${raw.slug}: ${raw.title} (${raw.total_chars} chars, ${raw.chunk_count} chunks)`
709	        );
710	      } catch { /* skip */ }
711	    }
712	    if (entries.length === 0) return "";
713	
714	    let block =
715	      "[Document indexes — use query_index or read tool to navigate tree, then read specific chunks]\n" +
716	      entries.join("\n") +
