739	
740	function buildScriptsBlock(): string {
741	  const scriptsDir = path.join(config.sessionCwd, "scripts");
742	  if (!existsSync(scriptsDir)) return "";
743	  try {
744	    const toolFiles = readdirSync(scriptsDir).filter(f => f.startsWith("tool-"));
