823	/**
824	 * Detect the agent's config home directory (e.g. ~/.kiro, ~/.codex, ~/.claude).
825	 * This is the parent of SKILL_DIR and also hosts agent-wide artefacts like
826	 * notebooklm-routing.json or agents/*.json. Env override: AGENT_CONFIG_DIR.
827	 */
828	export function detectAgentConfigDir(): string {
829	  const override = process.env.AGENT_CONFIG_DIR;
830	  if (override && override.trim() !== "") return path.resolve(override);
831	  const home = process.env.USERPROFILE || process.env.HOME || "";
832	  if (!home) return "(unknown — set $AGENT_CONFIG_DIR to override)";
833	  // Heuristic: the agent command name hints which CLI we're paired with.
834	  const agent = (config.agent?.command ?? "").toLowerCase();
835	  if (agent.includes("codex")) return path.join(home, ".codex");
836	  if (agent.includes("claude")) return path.join(home, ".claude");
837	  if (agent.includes("kiro")) return path.join(home, ".kiro");
838	  // Fallback: try .kiro then .codex
839	  const kiroDir = path.join(home, ".kiro");
840	  const codexDir = path.join(home, ".codex");
841	  if (existsSync(kiroDir)) return kiroDir;
842	  if (existsSync(codexDir)) return codexDir;
843	  return kiroDir; // best guess
844	}
845	
846	export function detectSkillDir(agentConfigDir?: string): string {
847	  // Prefer an explicit override so the user can point us at any directory.
848	  const override = process.env.SKILL_DIR;
849	  if (override && override.trim() !== "") return path.resolve(override);
850	  // Otherwise SKILL_DIR is just <agentConfigDir>/skills — keeps the two paths
851	  // aligned so users only need to override AGENT_CONFIG_DIR in unusual setups.
852	  const base = agentConfigDir ?? detectAgentConfigDir();
853	  if (base.startsWith("(unknown")) return "(unknown — set $SKILL_DIR to override)";
854	  return path.join(base, "skills");
855	}
856	
857	export function getFactsPath(userId: number): string {
858	  return factsPath(userId);
859	}
860	
861	export async function writeFacts(userId: number, lines: string[]): Promise<void> {
862	  await mkdir(config.memoryDir, { recursive: true });
863	  const ts = new Date().toISOString();
864	  const body = lines
865	    .map((l) => l.trim())
866	    .filter(Boolean)
867	    .map((l) => `- [${ts}] ${l}`)
868	    .join("\n");
869	  await writeFile(factsPath(userId), body + (body ? "\n" : ""), "utf8");
870	}
