248	        console.log(`[session] injected session archive for chat ${chatId} (${archive.stats.turnCount} turns, closed=${archive.closeReason})`);
249	      }
250	    } catch (err) {
251	      console.error(`[session] loadArchive failed for chat ${chatId}:`, (err as Error).message);
252	    }
253	
254	    // Inject pending dream suggestions (High Priority from last /dream run).
255	    // Read-only：STATE.md 由 dream 每晚重寫，這裡不刪。48h 新鮮度閘門防止
256	    // 注入陳年建議。Frozen-snapshot 合規：只在 create() 組一次，隨 preamble 凍結。
257	    let dreamStateBlock = "";
258	    try {
259	      const { readLoopStateHighPriority, loopStatePath } = await import("./loop-state.js");
260	      const hp = readLoopStateHighPriority();
261	      const fresh = hp?.lastRun && Date.now() - hp.lastRun.getTime() < 48 * 3600_000;
262	      if (hp && fresh && hp.items.length > 0) {
263	        dreamStateBlock =
264	          "\n[Pending dream suggestions — 上次 /dream 維運的 High Priority 待辦]\n" +
265	          hp.items.map((it) => `- ${it}`).join("\n") +
266	          "\n當使用者說「處理建議」「dream 建議」或類似語句時，即指上述項目。\n" +
267	          `完整三層清單（含 Watch List）在 ${loopStatePath()}。處理完某項後，更新該檔移除或標記已處理。\n` +
268	          "[End pending dream suggestions]\n\n";
269	        console.log(`[session] injected ${hp.items.length} pending dream suggestion(s) for chat ${chatId}`);
270	      }
271	    } catch { /* fail-open：STATE.md 缺失或格式不符不影響 session 建立 */ }
272	
273	    const relayTaskBlock = await formatActiveRelayTasksForPreamble(chatId);
274	    const preambleText = breakdown.text + workingStateBlock + archiveBlock + dreamStateBlock + relayTaskBlock;
275	    const provider = this.createProvider(activeType, env, preambleText);
276	    const session: ChatSession = {
277	      chatId,
278	      userId,
279	      client: provider,
280	      activeProvider: activeType,
281	      sessionId: "",
282	      lastUsed: Date.now(),
283	      buffer: "",
284	      toolLog: [],
285	      stderrTail: "",
286	      history: [],
287	      charsIn: 0,
288	      charsOut: 0,
289	      memoryPreamble: preambleText,
290	      preambleBreakdown: {
291	        total: preambleText.length,
292	        toolNotes: breakdown.toolNotes,
293	        envBlock: breakdown.envBlock,
294	        memoryBlock: breakdown.memoryBlock,
295	        dailylogBlock: breakdown.dailylogBlock,
296	      },
297	      preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection
298	      tailFacts: breakdown.tailFacts,
299	      injectedWikiSlugs: new Set(),
300	      injectedSkills: new Set(),
301	      inflight: false,
302	      _pendingMetaQueue: [],
303	      _consecutiveToolFails: 0,
304	      priorArchive,
305	    };
306	
307	    provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
308	    provider.on("stderr", (chunk) => {
309	      // Keep the tail so we can surface it with error messages.
310	      session.stderrTail = (session.stderrTail + chunk).slice(-2000);
311	      // Surface only when debugging; keep quiet otherwise.
312	      if (process.env.DEBUG_ACP) {
313	        console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
314	      }
315	    });
316	    provider.on("exit", (code) => {
317	      console.error(`[acp ${chatId}] agent exited (code=${code})`);
318	      // Only fire the unexpected-exit hook if this session is still registered.
319	      // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
320	      const stillRegistered = this.sessions.get(chatId) === session;
321	      if (stillRegistered) {
322	        this.sessions.delete(chatId);
323	        if (this.onUnexpectedExit) {
324	          this.onUnexpectedExit(session, code).catch((e) =>
325	            console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
326	          );
327	        }
328	      }
329	    });
330	
331	    session.sessionId = await provider.initialize();
332	    this.sessions.set(chatId, session);
333	    logEvent("session_start", { provider: activeType, sessionId: session.sessionId }, { chatId, userId });
334	    return session;
335	  }
