409	  private applyUpdate(session: ChatSession, u: SessionUpdate) {
410	    this.resetInactivityTimer(session);
411	    const up = u.update;
412	    // Opportunistically capture usage-like meta the agent may attach.
413	    const meta = (up as { _meta?: Record<string, unknown> })._meta;
414	    const usage =
415	      (meta?.usage as Record<string, unknown> | undefined) ??
416	      ((up as { usage?: Record<string, unknown> }).usage);
417	    if (usage && typeof usage === "object") {
418	      session.usage = usage;
419	    }
420	    switch (up.sessionUpdate) {
421	      case "agent_message_chunk":
422	      case "agent_thought_chunk": {
423	        const content = up.content as { type?: string; text?: string } | undefined;
424	        if (content?.type === "text" && typeof content.text === "string") {
425	          // Orphan turn: a message chunk arrived with no prompt turn in-flight
426	          // (typically a background sub-agent completion re-invoking the agent
427	          // via task-notification). The normal request→response flush path in
428	          // runPrompt isn't listening, so route it to the debounced orphan
429	          // flusher instead of the live-turn buffer. Thought chunks are never
430	          // user-facing, so only real message chunks take this path.
431	          if (up.sessionUpdate === "agent_message_chunk" && !session.inflight) {
432	            this.appendOrphan(session, content.text);
433	            break;
434	          }
435	          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
436	          if (up.sessionUpdate === "agent_thought_chunk") {
437	            session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
438	          } else {
439	            session.buffer += content.text;
440	            session.charsOut += content.text.length;
441	          }
442	          if (wasEmpty) petState("streaming");
443	          // Early-capture RELAY_DELEGATE tokens during streaming.
444	          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
445	          // but streaming chunks arrive unfiltered. We capture complete tokens here
446	          // so the final-render path can fall back to them if normal extraction finds nothing.
447	          // Inline/fenced code examples must stay inert, matching final token extraction.
448	          const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
449	          session._streamingDelegates = captured.length ? captured : undefined;
450	          session.onUpdate?.(session);
451	        }
452	        break;
453	      }
454	      case "tool_call": {
455	        const title = (up.title as string) ?? "tool";
456	        const startId = up.toolCallId as string | undefined;
457	        if (startId) (session._toolTitles ??= new Map()).set(startId, title);
458	        session.toolLog.push(`🔧 ${title}`);
459	        // Tier A precedingTools 唯一 push 維護點（避免 tool_call+update 兩處重複計數）。
460	        session._recentToolNames = appendToolName(session._recentToolNames ?? [], title);
461	        session._toolInFlight = true;
462	        petState("tool", title);
463	        session.onUpdate?.(session);
464	        break;
465	      }
466	      case "tool_call_update": {
467	        const status = up.status as string | undefined;
468	        const updId = up.toolCallId as string | undefined;
469	        // tool_call_update 只帶 opaque toolCallId、不帶 name。用 tool_call 起始時
470	        // 綁定的 title 解析工具名；退而用 inline title，再退用 "tool"。
471	        const toolName =
472	          (updId ? session._toolTitles?.get(updId) : undefined) ??
473	          (up.title as string) ??
474	          "tool";
475	        if (status === "completed") {
476	          session.toolLog.push(`✅ ${toolName}`);
477	          session._toolInFlight = false;
478	          session._consecutiveToolFails = 0;
479	          logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
480	          // Tier A seq observation：僅 ACP 路徑（Direct 由 tool-loop 的 Tier B rich 接手，避免雙記 BC-1）。
481	          // slice(0,-1) 排除「當前工具自身」（tool_call 已先 push title），對齊 rich 的「preceding 不含本 tool」語意。
482	          if (session.activeProvider === "acp") {
483	            recordSeqObservation({
484	              name: toolName,
485	              status: "completed",
486	              sessionId: session.sessionId,
487	              chatId: session.chatId,
488	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
489	            });
490	          }
491	          if (updId) session._toolTitles?.delete(updId);
492	          session.onUpdate?.(session);
493	        } else if (status === "failed") {
494	          session.toolLog.push(`❌ ${toolName}`);
495	          session._toolInFlight = false;
496	          session._consecutiveToolFails++;
497	          logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
498	          // Tier A seq observation：僅 ACP 路徑（Direct 失敗 tool 由 tool-loop catch 分支寫 rich）。
499	          if (session.activeProvider === "acp") {
500	            recordSeqObservation({
501	              name: toolName,
502	              status: "failed",
503	              sessionId: session.sessionId,
504	              chatId: session.chatId,
505	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
506	            });
507	          }
508	          if (updId) session._toolTitles?.delete(updId);
509	          if (session._consecutiveToolFails >= 2) {
510	            session.toolLog.push(
511	              `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
512	              `STOP and diagnose: what assumption is wrong? Try a different approach.`
513	            );
514	          }
515	          session.onUpdate?.(session);
516	        }
517	        break;
518	      }
519	      default:
520	        // Ignore plan/user_message_chunk/etc. for the bridge.
521	        break;
522	    }
523	  }
