525	  /**
526	   * Buffer an orphan-turn message chunk and (re)arm the quiescence timer.
527	   * Each new chunk pushes the flush out by orphanFlushQuiescenceMs so a
528	   * multi-chunk background summary is delivered as one message once the
529	   * agent goes quiet. No-op if the flusher is disabled (quiescence 0).
530	   */
531	  private appendOrphan(session: ChatSession, text: string) {
532	    if (config.orphanFlushQuiescenceMs <= 0) return;
533	    if (session._orphanSuppressUntil && Date.now() < session._orphanSuppressUntil) return;
534	    session._orphanBuffer = (session._orphanBuffer || "") + text;
535	    session.charsOut += text.length;
536	    if (session._orphanFlushTimer) clearTimeout(session._orphanFlushTimer);
537	    session._orphanFlushTimer = setTimeout(() => {
538	      session._orphanFlushTimer = undefined;
539	      this.flushOrphan(session);
540	    }, config.orphanFlushQuiescenceMs);
541	    session._orphanFlushTimer.unref?.();
542	  }
543	
544	  /**
545	   * Flush any buffered orphan-turn text immediately. Fired by the quiescence
546	   * timer, and eagerly at the start of a new live turn (resetTurn) so orphan
547	   * output never interleaves with the live turn's streaming placeholder.
548	   * Delivery itself is delegated to `onOrphanTurn` (run-prompt flusher).
549	   */
550	  flushOrphan(session: ChatSession) {
551	    if (session._orphanFlushTimer) {
552	      clearTimeout(session._orphanFlushTimer);
553	      session._orphanFlushTimer = undefined;
554	    }
555	    const text = (session._orphanBuffer || "").trim();
556	    session._orphanBuffer = undefined;
557	    if (!text) return;
558	    if (!this.onOrphanTurn) {
559	      console.warn(
560	        `[orphan ${session.chatId}] buffered ${text.length} chars but no onOrphanTurn handler wired — dropping`,
561	      );
562	      return;
563	    }
564	    console.log(`[orphan ${session.chatId}] flushing orphan turn (${text.length} chars)`);
565	    logEvent("orphan_flush", { chars: text.length }, { chatId: session.chatId, userId: session.userId });
566	    Promise.resolve(this.onOrphanTurn(session, text)).catch((err) =>
567	      console.error(`[orphan ${session.chatId}] onOrphanTurn failed:`, err),
568	    );
569	  }
570	
571	  resetTurn(session: ChatSession) {
572	    // Flush any pending orphan output before a new live turn clears the
573	    // buffers, so background continuation isn't lost or interleaved with the
574	    // upcoming turn's streaming placeholder.
575	    if (session._orphanBuffer || session._orphanFlushTimer) this.flushOrphan(session);
576	    session._orphanSuppressUntil = undefined;
577	    session.buffer = "";
578	    session.thinkingBuffer = undefined;
579	    session.toolLog = [];
580	    session.stderrTail = "";
581	    session._toolInFlight = false;
582	    session._streamingDelegates = undefined;
583	    session._toolTitles?.clear();
584	    // push turn 邊界 marker 但「不清空」_recentToolNames——硬清空會讓每 turn 第一個
585	    // tool 的 precedingTools 永遠空；marker 讓下游 analyzer 自己切斷跨 turn combo。
586	    if (session._recentToolNames?.length) {
587	      session._recentToolNames = appendToolName(session._recentToolNames, TURN_MARKER);
588	    }
589	    this.startInactivityTimer(session);
590	  }
