592	  cancel(chatId: number) {
593	    const s = this.sessions.get(chatId);
594	    if (!s) return;
595	    s.client.cancel();
596	
597	    // Optimistic cancel: immediately free the session so the user can send
598	    // new messages without waiting for the CLI to acknowledge cancellation.
599	    s._cancelledTurn = true;
600	    s.inflight = false;
601	    s._toolInFlight = false;
602	    s.onUpdate = undefined;
603	    this.clearInactivityTimer(s);
604	    // Drop any orphan capture in progress: after cancel, inflight=false means
605	    // trailing chunks from the cancelled turn would flip to the orphan path.
606	    // A cancel means "stop, I don't want this" — discard rather than flush
607	    // abandoned partial output. Genuine later background output re-arms fresh.
608	    if (s._orphanFlushTimer) { clearTimeout(s._orphanFlushTimer); s._orphanFlushTimer = undefined; }
609	    s._orphanBuffer = undefined;
610	    // Suppress capture across the force-kill window so trailing chunks don't leak.
611	    s._orphanSuppressUntil = Date.now() + 20_000;
612	
613	    // Force-kill escalation: if CLI doesn't exit the turn within 15s,
614	    // kill the process tree and re-create on next message.
615	    if (!s.client.isClosed) {
616	      const timer = setTimeout(async () => {
617	        if (s.client.isClosed) return;
618	        console.warn(`[cancel] chat ${chatId} CLI still alive after 15s — force-killing`);
619	        await s.client.close();
620	      }, 15_000);
621	      timer.unref?.();
622	    }
623	  }
