625	  /** Enable drop-all mode: silently discard messages sent before now. */
626	  enableDropAll(chatId: number) { this._dropBefore.set(chatId, Math.floor(Date.now() / 1000)); }
627	  /** Disable drop-all mode. */
628	  disableDropAll(chatId: number) { this._dropBefore.delete(chatId); }
629	  /** Check if a message should be dropped (sent before the cutoff). */
630	  shouldDrop(chatId: number, messageDate: number): boolean {
631	    const cutoff = this._dropBefore.get(chatId);
632	    if (!cutoff) return false;
633	    if (messageDate <= cutoff) return true;
634	    // Message is newer than cutoff — auto-clear and let it through
635	    this._dropBefore.delete(chatId);
636	    return false;
637	  }
