647	  /**
648	   * Persist a closing session's archive, or carry the prior archive forward.
649	   *
650	   * A "substantive" close (>= config.archiveMinTurns turns with some assistant
651	   * output) is exported — including a close-time LLM summary — and saved. A
652	   * trivial close does NOT overwrite a more-substantive prior archive: the
653	   * stashed priorArchive is re-saved so the real work's context survives to the
654	   * next session. exportSession itself skips the LLM summary for crash /
655	   * health_monitor closes (process dying) and falls back to truncation.
656	   */
657	  private async archiveOnClose(s: ChatSession, closeReason: SessionArchive["closeReason"]) {
658	    const assistantChars = s.history.reduce(
659	      (n, h) => (h.role === "assistant" ? n + h.text.length : n),
660	      0,
661	    );
662	    const substantive = s.history.length >= config.archiveMinTurns && assistantChars > 0;
663	    try {
664	      if (substantive) {
665	        await saveArchive(await exportSession(s, closeReason));
666	      } else if (s.priorArchive) {
667	        // Trivial close — keep the prior, more-substantive archive.
668	        await saveArchive(s.priorArchive);
669	        console.log(`[archive] chat ${s.chatId}: trivial close (${s.history.length} turns), carried prior archive forward`);
670	      } else if (s.history.length > 0) {
671	        // No prior to fall back to — persist what little we have.
672	        await saveArchive(await exportSession(s, closeReason));
673	      }
674	    } catch (e) {
675	      console.error(`[session ${s.chatId}] archive failed:`, e);
676	    }
677	  }
