679	  async drop(chatId: number, closeReason: "manual" | "reset" | "restart" = "manual") {
680	    const s = this.sessions.get(chatId);
681	    if (!s) return;
682	    this.sessions.delete(chatId);
683	    // Archive session state before closing (summary + trivial carry-forward)
684	    if (s.history.length > 0 || s.priorArchive) {
685	      await this.archiveOnClose(s, closeReason);
686	    }
687	    if (this.onBeforeClose) {
688	      try { await this.onBeforeClose(s); } catch (e) {
689	        console.error(`[session ${chatId}] onBeforeClose failed:`, e);
690	      }
691	    }
692	    await s.client.close();
693	  }
