695	  private async sweepIdle() {
696	    const now = Date.now();
697	    for (const [chatId, s] of this.sessions) {
698	      // --- Runtime Health Monitor ---
699	      // Detect subprocess that silently died (pid no longer valid) but
700	      // exit event hasn't fired yet (possible on Windows when parent shell
701	      // exits but Node doesn't see the signal).
702	      const clientPid = "pid" in s.client ? (s.client as { pid?: number }).pid : undefined;
703	      if (!s.client.isClosed && clientPid !== undefined) {
704	        try {
705	          // process.kill(pid, 0) throws if pid doesn't exist — non-destructive probe
706	          process.kill(clientPid, 0);
707	        } catch {
708	          // Process is gone but client didn't fire exit event
709	          console.error(`[health] chat ${chatId}: ACP subprocess (pid=${clientPid}) is dead, forcing cleanup`);
710	          logEvent("session_end", { reason: "health_monitor_dead_process" }, { chatId, userId: s.userId });
711	          this.sessions.delete(chatId);
712	          // Preserve context: archive what streamed, or carry the prior archive
713	          // forward (it was already deleted from disk when this session started).
714	          if (s.history.length > 0 || s.priorArchive) {
715	            await this.archiveOnClose(s, "health_monitor");
716	          }
717	          s.client.close().catch(() => {});
718	          if (this.onUnexpectedExit) {
719	            this.onUnexpectedExit(s, null).catch((e) =>
720	              console.error(`[health ${chatId}] onUnexpectedExit failed:`, e),
721	            );
722	          }
723	          continue; // skip idle check for this session
724	        }
725	      }
726	
727	      // --- Idle timeout sweep ---
728	      if (now - s.lastUsed > config.sessionIdleMs) {
729	        console.log(`[session] dropping idle chat ${chatId}`);
730	        this.sessions.delete(chatId);
731	        // Archive session state before closing (summary + trivial carry-forward)
732	        if (s.history.length > 0 || s.priorArchive) {
733	          await this.archiveOnClose(s, "idle");
734	        }
735	        if (this.onBeforeClose) {
736	          try { await this.onBeforeClose(s); } catch (e) {
737	            console.error(`[session ${chatId}] onBeforeClose failed:`, e);
738	          }
739	        }
740	        s.client.close().catch(() => {});
741	      }
742	    }
743	  }
744	
745	  async shutdown() {
746	    clearInterval(this.sweeper);
747	    const all = Array.from(this.sessions.values());
748	    this.sessions.clear();
749	    console.log(`[session] shutdown: flushing ${all.length} session(s)`);
750	    // Archive all sessions before closing (summary + trivial carry-forward)
751	    for (const s of all) {
752	      if (!s.client.isClosed && (s.history.length > 0 || s.priorArchive)) {
753	        await this.archiveOnClose(s, "restart");
754	      }
755	    }
756	    if (this.onBeforeClose) {
757	      for (const s of all) {
758	        if (s.client.isClosed) {
