import { readFile, unlink } from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import { loadFacts, buildPreambleWithBreakdown, buildLocalPreamble } from "./memory.js";
import { formatActiveRelayTasksForPreamble } from "./working-state.js";
import { petState } from "./pet-server.js";
import { AcpProvider, DirectProvider, resolveBaseUrl, type Provider, type ProviderType, type SessionUpdate } from "./provider/index.js";
import { logEvent } from "./event-log.js";
import { recordSeqObservation, appendToolName, TURN_MARKER } from "./tool-observer.js";
import { exportSession, saveArchive, type SessionArchive } from "./session-archive.js";

const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;

function maskCodeRegionsForRelayCapture(text: string): { masked: string; restore: (s: string) => string } {
  const slots: string[] = [];
  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
    const idx = slots.length;
    slots.push(m);
    return `\u0000CODE${idx}\u0000`;
  });
  const restore = (s: string) =>
    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
  return { masked, restore };
}

export function isRelayDelegatePlaceholderGoal(goal: string): boolean {
  const g = goal.trim();
  return g === "" || g === "..." || g === "…" || /^<[^>\r\n]*>?$/.test(g);
}

export function captureRelayDelegateTokensFromText(buffer: string, existing: string[] = []): string[] {
  const next = [...existing];
  const { masked, restore } = maskCodeRegionsForRelayCapture(buffer);
  let m: RegExpExecArray | null;
  RELAY_DELEGATE_RE.lastIndex = 0;
  while ((m = RELAY_DELEGATE_RE.exec(masked)) !== null) {
    const goal = m[2]?.trim() ?? "";
    if (isRelayDelegatePlaceholderGoal(goal)) continue;
    const token = restore(m[0]);
    if (!next.includes(token)) next.push(token);
  }
  return next;
}

export interface HistoryEntry {
  role: "user" | "assistant";
  text: string;
  timestamp: number;
}

/**
 * Per-Telegram-chat session. Each chat owns its own Kiro ACP subprocess,
 * so conversations stay isolated.
 */
export interface ChatSession {
  chatId: number;
  userId?: number;
  client: Provider;
  /** Which provider type is active for this session. */
  activeProvider: ProviderType;
  sessionId: string;
  lastUsed: number;
  /** Accumulated assistant text for the in-flight turn. */
  buffer: string;
  /** Accumulated thinking text for the in-flight turn (local model only). */
  thinkingBuffer?: string;
  /** Human-readable tool/status lines for the in-flight turn. */
  toolLog: string[];
  /** Rolling buffer of the agent's latest stderr output. */
  stderrTail: string;
  /** Called whenever new streamed text is appended. */
  onUpdate?: (session: ChatSession) => void;
  /** Conversation history for /save export. */
  history: HistoryEntry[];
  /** Cumulative characters sent by user (approximate context-in). */
  charsIn: number;
  /** Cumulative characters emitted by agent (approximate context-out). */
  charsOut: number;
  /** Latest usage meta reported by agent (tokens, etc.), if any. */
  usage?: Record<string, unknown>;
  /** Long-term memory preamble to inject on first prompt. */
  memoryPreamble: string;
  /**
   * Char-length breakdown of `memoryPreamble`. Captured once at session
   * create so the /context and streaming-footer UI can show where the
   * preamble tokens are going (tool notes / env block / memory block)
   * without having to re-measure the string.
   */
  preambleBreakdown: {
    total: number;
    toolNotes: number;
    envBlock: number;
    memoryBlock: number;
    dailylogBlock: number;
  };
  /** Set true after first prompt so we inject preamble only once. */
  preambleInjected: boolean;
  /** Stripped tail facts from preamble — used by memory-recall dedup. */
  tailFacts: Set<string>;
  /** Wiki slugs already injected this session — skip on subsequent turns. */
  injectedWikiSlugs: Set<string>;
  /** Skill names already injected this session — skip on subsequent turns. */
  injectedSkills: Set<string>;
  /**
   * True while a session/prompt call is in-flight against this session's
   * ACP client. kiro-cli rejects concurrent prompts with
   * `-32603 Prompt already in progress`; callers must check this flag
   * before calling `client.prompt()` and bail out with a friendly message
   * instead of racing.
   */
  inflight: boolean;
  /** Internal: inactivity timer handle for the current turn. */
  _inactivityTimer?: NodeJS.Timeout;
  /** Internal: true while a tool_call has started but not yet completed/failed. */
  _toolInFlight?: boolean;
  /** Internal: RELAY_DELEGATE tokens captured during streaming (workaround for CLI stripping tokens from final text). */
  _streamingDelegates?: string[];
  /** Path of the most recent user upload in this turn (consumed by RELAY_DELEGATE auto-attach). */
  _lastUploadPath?: string;
  /** Internal: meta prompts queued while session was inflight (e.g. parallel delegate results). Drained after inflight=false. */
  _pendingMetaQueue: Array<{ ctx: unknown; prompt: string; opts: Record<string, unknown> }>;
  /** Internal: consecutive tool call failures for reflexion hint injection. */
  _consecutiveToolFails: number;
  /**
   * Internal: 把 tool_call 起始時的 human-readable title 綁到 opaque toolCallId，
   * 供 tool_call_update（只帶 id 不帶 name）解析工具名。用完即刪。
   */
  _toolTitles?: Map<string, string>;
  /**
   * Internal: rolling 純工具名序列（含 turn 邊界 marker），供 Tier A seq observation 的
   * precedingTools。僅在 tool_call case 維護一處 push；resetTurn 推入 TURN_MARKER 不清空。
   */
  _recentToolNames?: string[];
  /** Internal: set true when cancel() fires; run-prompt finally skips post-processing. */
  _cancelledTurn?: boolean;
  /** Internal: message_id of the current turn's placeholder (for cancel UI feedback). */
  _placeholderMsgId?: number;
  /** Internal: true once the 70% context budget warning has been injected this session. */
  _budgetWarned?: boolean;
  /**
   * Internal: accumulates agent_message_chunk text that arrives while NO
   * prompt turn is in-flight (an "orphan turn" — typically a Claude Code
   * harness background sub-agent completing and re-invoking the agent via
   * task-notification). Kept separate from `buffer` so a subsequent live
   * turn's resetTurn can't clobber it. Flushed by the orphan-turn-flusher.
   */
  _orphanBuffer?: string;
  /** Internal: debounce timer for the orphan-turn flush (armed per chunk). */
  _orphanFlushTimer?: NodeJS.Timeout;
  /**
   * Internal: epoch-ms until which orphan capture is suppressed. Set on
   * cancel so trailing chunks from the cancelled turn (which arrive after
   * inflight flips false) are dropped instead of flushed. Genuine background
   * output arriving after this window still flushes normally.
   */
  _orphanSuppressUntil?: number;
  /**
   * Internal: the archive loaded from the PREVIOUS session at create time
   * (already consumed/deleted from disk on inject). Stashed so that if THIS
   * session turns out trivial (< config.archiveMinTurns), archiveOnClose can
   * carry the prior, more-substantive archive forward instead of clobbering it
   * with a throwaway one. undefined if there was no prior archive.
   */
  priorArchive?: SessionArchive;
}

export class SessionManager {
  private sessions = new Map<number, ChatSession>();
  private sweeper: NodeJS.Timeout;
  /** Per-chat: messages with date <= this value are silently dropped. */
  private _dropBefore = new Map<number, number>();
  /** Called before a session's agent is closed. Used for memory extraction. */
  public onBeforeClose?: (session: ChatSession) => Promise<void>;
  /** Called when the agent exits unexpectedly (crash, kill). Best-effort persistence only. */
  public onUnexpectedExit?: (session: ChatSession, code: number | null) => Promise<void>;
  /**
   * Called when an orphan turn (agent output produced with no active prompt
   * turn) quiesces. Wired in index.ts to the run-prompt flusher so orphan
   * delivery reuses the SAME reply transform / render / token path as the
   * normal request→response flow. `text` is the raw accumulated buffer.
   */
  public onOrphanTurn?: (session: ChatSession, text: string) => void | Promise<void>;

  constructor() {
    this.sweeper = setInterval(() => this.sweepIdle(), 60_000);
    this.sweeper.unref?.();
  }

  async get(chatId: number, userId?: number): Promise<ChatSession> {
    const existing = this.sessions.get(chatId);
    if (existing && !existing.client.isClosed) {
      existing.lastUsed = Date.now();
      return existing;
    }
    return this.create(chatId, userId);
  }

  private async create(chatId: number, userId?: number, providerType?: ProviderType): Promise<ChatSession> {
    // Inject TG_ACTIVE_USER_ID so MCP children (mcp-memory) know whose
    // facts file to write. MEMORY_DIR is passed through too so the mcp
    // server doesn't need to re-read .env.
    const env: Record<string, string> = { MEMORY_DIR: config.memoryDir };
    if (userId) env.TG_ACTIVE_USER_ID = String(userId);

    const activeType = providerType ?? config.defaultProvider;
    const facts = userId ? await loadFacts(userId) : "";

    // Try to compress recent facts via local LLM (graceful fallback if unavailable)
    let compressed: string | null = null;
    if (facts && activeType !== "local") {
      const lines = facts.split(/\r?\n/).filter(l => l.trim().length > 0);
      const tail = config.memoryPreambleTail;
      if (lines.length > tail) {
        const { compressFactsForPreamble: compress } = await import("./local-llm.js");
        compressed = await compress(lines.slice(-tail));
      }
    }
    const breakdown = activeType === "local"
      ? buildLocalPreamble(facts, userId)
      : buildPreambleWithBreakdown(facts, userId, { compressed });

    // Inject working-state from previous session if available (one-shot).
    const wsPath = path.join(config.memoryDir, `working-state-${chatId}.md`);
    let workingStateBlock = "";
    try {
      const ws = await readFile(wsPath, "utf8");
      workingStateBlock =
        "\n[Previous session working state — use as context to resume work]\n" +
        ws +
        "\nResume from `next_action` above. Do not ask what was done last time.\n" +
        "[End working state]\n\n";
      await unlink(wsPath);
      console.log(`[session] injected working-state for chat ${chatId}`);
    } catch { /* file doesn't exist — normal */ }

    // Inject structured session archive restoration (complements working-state
    // with turn-level context, goal state, and session stats).
    let archiveBlock = "";
    let priorArchive: SessionArchive | undefined;
    try {
      const { loadArchive, buildRestorationBlock, deleteArchive } = await import("./session-archive.js");
      const archive = await loadArchive(chatId);
      if (archive) {
        archiveBlock = "\n" + buildRestorationBlock(archive) + "\n\n";
        await deleteArchive(chatId);
        priorArchive = archive; // stash for trivial-session carry-forward on close
        console.log(`[session] injected session archive for chat ${chatId} (${archive.stats.turnCount} turns, closed=${archive.closeReason})`);
      }
    } catch (err) {
      console.error(`[session] loadArchive failed for chat ${chatId}:`, (err as Error).message);
    }

    // Inject pending dream suggestions (High Priority from last /dream run).
    // Read-only：STATE.md 由 dream 每晚重寫，這裡不刪。48h 新鮮度閘門防止
    // 注入陳年建議。Frozen-snapshot 合規：只在 create() 組一次，隨 preamble 凍結。
    let dreamStateBlock = "";
    try {
      const { readLoopStateHighPriority, loopStatePath } = await import("./loop-state.js");
      const hp = readLoopStateHighPriority();
      const fresh = hp?.lastRun && Date.now() - hp.lastRun.getTime() < 48 * 3600_000;
      if (hp && fresh && hp.items.length > 0) {
        dreamStateBlock =
          "\n[Pending dream suggestions — 上次 /dream 維運的 High Priority 待辦]\n" +
          hp.items.map((it) => `- ${it}`).join("\n") +
          "\n當使用者說「處理建議」「dream 建議」或類似語句時，即指上述項目。\n" +
          `完整三層清單（含 Watch List）在 ${loopStatePath()}。處理完某項後，更新該檔移除或標記已處理。\n` +
          "[End pending dream suggestions]\n\n";
        console.log(`[session] injected ${hp.items.length} pending dream suggestion(s) for chat ${chatId}`);
      }
    } catch { /* fail-open：STATE.md 缺失或格式不符不影響 session 建立 */ }

    const relayTaskBlock = await formatActiveRelayTasksForPreamble(chatId);
    const preambleText = breakdown.text + workingStateBlock + archiveBlock + dreamStateBlock + relayTaskBlock;
    const provider = this.createProvider(activeType, env, preambleText);
    const session: ChatSession = {
      chatId,
      userId,
      client: provider,
      activeProvider: activeType,
      sessionId: "",
      lastUsed: Date.now(),
      buffer: "",
      toolLog: [],
      stderrTail: "",
      history: [],
      charsIn: 0,
      charsOut: 0,
      memoryPreamble: preambleText,
      preambleBreakdown: {
        total: preambleText.length,
        toolNotes: breakdown.toolNotes,
        envBlock: breakdown.envBlock,
        memoryBlock: breakdown.memoryBlock,
        dailylogBlock: breakdown.dailylogBlock,
      },
      preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection
      tailFacts: breakdown.tailFacts,
      injectedWikiSlugs: new Set(),
      injectedSkills: new Set(),
      inflight: false,
      _pendingMetaQueue: [],
      _consecutiveToolFails: 0,
      priorArchive,
    };

    provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
    provider.on("stderr", (chunk) => {
      // Keep the tail so we can surface it with error messages.
      session.stderrTail = (session.stderrTail + chunk).slice(-2000);
      // Surface only when debugging; keep quiet otherwise.
      if (process.env.DEBUG_ACP) {
        console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
      }
    });
    provider.on("exit", (code) => {
      console.error(`[acp ${chatId}] agent exited (code=${code})`);
      // Only fire the unexpected-exit hook if this session is still registered.
      // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
      const stillRegistered = this.sessions.get(chatId) === session;
      if (stillRegistered) {
        this.sessions.delete(chatId);
        if (this.onUnexpectedExit) {
          this.onUnexpectedExit(session, code).catch((e) =>
            console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
          );
        }
      }
    });

    session.sessionId = await provider.initialize();
    this.sessions.set(chatId, session);
    logEvent("session_start", { provider: activeType, sessionId: session.sessionId }, { chatId, userId });
    return session;
  }

  /** Factory: create the right Provider based on type. */
  private createProvider(type: ProviderType, env: Record<string, string>, systemPrompt?: string): Provider {
    if (type === "acp") {
      return new AcpProvider({
        command: config.agent.command,
        args: config.agent.args,
        cwd: config.sessionCwd,
        env,
        promptRetries: config.acpPromptRetries,
        promptRetryBaseMs: config.acpPromptRetryBaseMs,
        acpModel: config.acpModel,
        acpEffort: config.acpEffort,
        sessionCwd: config.sessionCwd,
      });
    }
    // All other types use DirectProvider
    const modelKey = type as keyof typeof config.models;
    const apiKeyKey = type as keyof typeof config.apiKeys;
    return new DirectProvider({
      type,
      model: config.models[modelKey] ?? config.models.local,
      baseUrl: resolveBaseUrl(type, config.ollamaUrl),
      apiKey: config.apiKeys[apiKeyKey] ?? "",
      systemPrompt,
      mcpEnv: env,
      // Local models have limited context — keep the server set focused.
      mcpServerFilter: type === "local" ? ["memory", "notebooklm", "google"] : undefined,
    });
  }

  /**
   * Switch the active provider for a chat. Closes the old session and
   * creates a new one with the specified provider type.
   * Returns the new session.
   */
  async switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession> {
    const existing = this.sessions.get(chatId);
    if (existing) {
      this.sessions.delete(chatId);
      await existing.client.close().catch(() => {});
    }
    return this.create(chatId, userId, type);
  }

  /** Start (or restart) the inactivity timer for a turn. */
  startInactivityTimer(session: ChatSession) {
    this.clearInactivityTimer(session);
    const ms = session._toolInFlight && config.turnToolInactivityTimeoutMs > 0
      ? config.turnToolInactivityTimeoutMs
      : config.turnInactivityTimeoutMs;
    if (ms <= 0) return;
    session._inactivityTimer = setTimeout(() => {
      console.warn(
        `[session ${session.chatId}] turn inactivity timeout (${ms}ms, toolInFlight=${!!session._toolInFlight}) — auto-cancelling`,
      );
      session.client.cancel();
    }, ms);
    session._inactivityTimer.unref?.();
  }

  private resetInactivityTimer(session: ChatSession) {
    if (!session._inactivityTimer) return;
    this.startInactivityTimer(session);
  }

  clearInactivityTimer(session: ChatSession) {
    if (session._inactivityTimer) {
      clearTimeout(session._inactivityTimer);
      session._inactivityTimer = undefined;
    }
  }

  private applyUpdate(session: ChatSession, u: SessionUpdate) {
    this.resetInactivityTimer(session);
    const up = u.update;
    // Opportunistically capture usage-like meta the agent may attach.
    const meta = (up as { _meta?: Record<string, unknown> })._meta;
    const usage =
      (meta?.usage as Record<string, unknown> | undefined) ??
      ((up as { usage?: Record<string, unknown> }).usage);
    if (usage && typeof usage === "object") {
      session.usage = usage;
    }
    switch (up.sessionUpdate) {
      case "agent_message_chunk":
      case "agent_thought_chunk": {
        const content = up.content as { type?: string; text?: string } | undefined;
        if (content?.type === "text" && typeof content.text === "string") {
          // Orphan turn: a message chunk arrived with no prompt turn in-flight
          // (typically a background sub-agent completion re-invoking the agent
          // via task-notification). The normal request→response flush path in
          // runPrompt isn't listening, so route it to the debounced orphan
          // flusher instead of the live-turn buffer. Thought chunks are never
          // user-facing, so only real message chunks take this path.
          if (up.sessionUpdate === "agent_message_chunk" && !session.inflight) {
            this.appendOrphan(session, content.text);
            break;
          }
          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
          if (up.sessionUpdate === "agent_thought_chunk") {
            session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
          } else {
            session.buffer += content.text;
            session.charsOut += content.text.length;
          }
          if (wasEmpty) petState("streaming");
          // Early-capture RELAY_DELEGATE tokens during streaming.
          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
          // but streaming chunks arrive unfiltered. We capture complete tokens here
          // so the final-render path can fall back to them if normal extraction finds nothing.
          // Inline/fenced code examples must stay inert, matching final token extraction.
          const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
          session._streamingDelegates = captured.length ? captured : undefined;
          session.onUpdate?.(session);
        }
        break;
      }
      case "tool_call": {
        const title = (up.title as string) ?? "tool";
        const startId = up.toolCallId as string | undefined;
        if (startId) (session._toolTitles ??= new Map()).set(startId, title);
        session.toolLog.push(`🔧 ${title}`);
        // Tier A precedingTools 唯一 push 維護點（避免 tool_call+update 兩處重複計數）。
        session._recentToolNames = appendToolName(session._recentToolNames ?? [], title);
        session._toolInFlight = true;
        petState("tool", title);
        session.onUpdate?.(session);
        break;
      }
      case "tool_call_update": {
        const status = up.status as string | undefined;
        const updId = up.toolCallId as string | undefined;
        // tool_call_update 只帶 opaque toolCallId、不帶 name。用 tool_call 起始時
        // 綁定的 title 解析工具名；退而用 inline title，再退用 "tool"。
        const toolName =
          (updId ? session._toolTitles?.get(updId) : undefined) ??
          (up.title as string) ??
          "tool";
        if (status === "completed") {
          session.toolLog.push(`✅ ${toolName}`);
          session._toolInFlight = false;
          session._consecutiveToolFails = 0;
          logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
          // Tier A seq observation：僅 ACP 路徑（Direct 由 tool-loop 的 Tier B rich 接手，避免雙記 BC-1）。
          // slice(0,-1) 排除「當前工具自身」（tool_call 已先 push title），對齊 rich 的「preceding 不含本 tool」語意。
          if (session.activeProvider === "acp") {
            recordSeqObservation({
              name: toolName,
              status: "completed",
              sessionId: session.sessionId,
              chatId: session.chatId,
              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
            });
          }
          if (updId) session._toolTitles?.delete(updId);
          session.onUpdate?.(session);
        } else if (status === "failed") {
          session.toolLog.push(`❌ ${toolName}`);
          session._toolInFlight = false;
          session._consecutiveToolFails++;
          logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
          // Tier A seq observation：僅 ACP 路徑（Direct 失敗 tool 由 tool-loop catch 分支寫 rich）。
          if (session.activeProvider === "acp") {
            recordSeqObservation({
              name: toolName,
              status: "failed",
              sessionId: session.sessionId,
              chatId: session.chatId,
              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
            });
          }
          if (updId) session._toolTitles?.delete(updId);
          if (session._consecutiveToolFails >= 2) {
            session.toolLog.push(
              `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
              `STOP and diagnose: what assumption is wrong? Try a different approach.`
            );
          }
          session.onUpdate?.(session);
        }
        break;
      }
      default:
        // Ignore plan/user_message_chunk/etc. for the bridge.
        break;
    }
  }

  /**
   * Buffer an orphan-turn message chunk and (re)arm the quiescence timer.
   * Each new chunk pushes the flush out by orphanFlushQuiescenceMs so a
   * multi-chunk background summary is delivered as one message once the
   * agent goes quiet. No-op if the flusher is disabled (quiescence 0).
   */
  private appendOrphan(session: ChatSession, text: string) {
    if (config.orphanFlushQuiescenceMs <= 0) return;
    if (session._orphanSuppressUntil && Date.now() < session._orphanSuppressUntil) return;
    session._orphanBuffer = (session._orphanBuffer || "") + text;
    session.charsOut += text.length;
    if (session._orphanFlushTimer) clearTimeout(session._orphanFlushTimer);
    session._orphanFlushTimer = setTimeout(() => {
      session._orphanFlushTimer = undefined;
      this.flushOrphan(session);
    }, config.orphanFlushQuiescenceMs);
    session._orphanFlushTimer.unref?.();
  }

  /**
   * Flush any buffered orphan-turn text immediately. Fired by the quiescence
   * timer, and eagerly at the start of a new live turn (resetTurn) so orphan
   * output never interleaves with the live turn's streaming placeholder.
   * Delivery itself is delegated to `onOrphanTurn` (run-prompt flusher).
   */
  flushOrphan(session: ChatSession) {
    if (session._orphanFlushTimer) {
      clearTimeout(session._orphanFlushTimer);
      session._orphanFlushTimer = undefined;
    }
    const text = (session._orphanBuffer || "").trim();
    session._orphanBuffer = undefined;
    if (!text) return;
    if (!this.onOrphanTurn) {
      console.warn(
        `[orphan ${session.chatId}] buffered ${text.length} chars but no onOrphanTurn handler wired — dropping`,
      );
      return;
    }
    console.log(`[orphan ${session.chatId}] flushing orphan turn (${text.length} chars)`);
    logEvent("orphan_flush", { chars: text.length }, { chatId: session.chatId, userId: session.userId });
    Promise.resolve(this.onOrphanTurn(session, text)).catch((err) =>
      console.error(`[orphan ${session.chatId}] onOrphanTurn failed:`, err),
    );
  }

  resetTurn(session: ChatSession) {
    // Flush any pending orphan output before a new live turn clears the
    // buffers, so background continuation isn't lost or interleaved with the
    // upcoming turn's streaming placeholder.
    if (session._orphanBuffer || session._orphanFlushTimer) this.flushOrphan(session);
    session._orphanSuppressUntil = undefined;
    session.buffer = "";
    session.thinkingBuffer = undefined;
    session.toolLog = [];
    session.stderrTail = "";
    session._toolInFlight = false;
    session._streamingDelegates = undefined;
    session._toolTitles?.clear();
    // push turn 邊界 marker 但「不清空」_recentToolNames——硬清空會讓每 turn 第一個
    // tool 的 precedingTools 永遠空；marker 讓下游 analyzer 自己切斷跨 turn combo。
    if (session._recentToolNames?.length) {
      session._recentToolNames = appendToolName(session._recentToolNames, TURN_MARKER);
    }
    this.startInactivityTimer(session);
  }

  cancel(chatId: number) {
    const s = this.sessions.get(chatId);
    if (!s) return;
    s.client.cancel();

    // Optimistic cancel: immediately free the session so the user can send
    // new messages without waiting for the CLI to acknowledge cancellation.
    s._cancelledTurn = true;
    s.inflight = false;
    s._toolInFlight = false;
    s.onUpdate = undefined;
    this.clearInactivityTimer(s);
    // Drop any orphan capture in progress: after cancel, inflight=false means
    // trailing chunks from the cancelled turn would flip to the orphan path.
    // A cancel means "stop, I don't want this" — discard rather than flush
    // abandoned partial output. Genuine later background output re-arms fresh.
    if (s._orphanFlushTimer) { clearTimeout(s._orphanFlushTimer); s._orphanFlushTimer = undefined; }
    s._orphanBuffer = undefined;
    // Suppress capture across the force-kill window so trailing chunks don't leak.
    s._orphanSuppressUntil = Date.now() + 20_000;

    // Force-kill escalation: if CLI doesn't exit the turn within 15s,
    // kill the process tree and re-create on next message.
    if (!s.client.isClosed) {
      const timer = setTimeout(async () => {
        if (s.client.isClosed) return;
        console.warn(`[cancel] chat ${chatId} CLI still alive after 15s — force-killing`);
        await s.client.close();
      }, 15_000);
      timer.unref?.();
    }
  }

  /** Enable drop-all mode: silently discard messages sent before now. */
  enableDropAll(chatId: number) { this._dropBefore.set(chatId, Math.floor(Date.now() / 1000)); }
  /** Disable drop-all mode. */
  disableDropAll(chatId: number) { this._dropBefore.delete(chatId); }
  /** Check if a message should be dropped (sent before the cutoff). */
  shouldDrop(chatId: number, messageDate: number): boolean {
    const cutoff = this._dropBefore.get(chatId);
    if (!cutoff) return false;
    if (messageDate <= cutoff) return true;
    // Message is newer than cutoff — auto-clear and let it through
    this._dropBefore.delete(chatId);
    return false;
  }

  peek(chatId: number): ChatSession | undefined {
    return this.sessions.get(chatId);
  }

  size(): number {
    return this.sessions.size;
  }

  /**
   * Persist a closing session's archive, or carry the prior archive forward.
   *
   * A "substantive" close (>= config.archiveMinTurns turns with some assistant
   * output) is exported — including a close-time LLM summary — and saved. A
   * trivial close does NOT overwrite a more-substantive prior archive: the
   * stashed priorArchive is re-saved so the real work's context survives to the
   * next session. exportSession itself skips the LLM summary for crash /
   * health_monitor closes (process dying) and falls back to truncation.
   */
  private async archiveOnClose(s: ChatSession, closeReason: SessionArchive["closeReason"]) {
    const assistantChars = s.history.reduce(
      (n, h) => (h.role === "assistant" ? n + h.text.length : n),
      0,
    );
    const substantive = s.history.length >= config.archiveMinTurns && assistantChars > 0;
    try {
      if (substantive) {
        await saveArchive(await exportSession(s, closeReason));
      } else if (s.priorArchive) {
        // Trivial close — keep the prior, more-substantive archive.
        await saveArchive(s.priorArchive);
        console.log(`[archive] chat ${s.chatId}: trivial close (${s.history.length} turns), carried prior archive forward`);
      } else if (s.history.length > 0) {
        // No prior to fall back to — persist what little we have.
        await saveArchive(await exportSession(s, closeReason));
      }
    } catch (e) {
      console.error(`[session ${s.chatId}] archive failed:`, e);
    }
  }

  async drop(chatId: number, closeReason: "manual" | "reset" | "restart" = "manual") {
    const s = this.sessions.get(chatId);
    if (!s) return;
    this.sessions.delete(chatId);
    // Archive session state before closing (summary + trivial carry-forward)
    if (s.history.length > 0 || s.priorArchive) {
      await this.archiveOnClose(s, closeReason);
    }
    if (this.onBeforeClose) {
      try { await this.onBeforeClose(s); } catch (e) {
        console.error(`[session ${chatId}] onBeforeClose failed:`, e);
      }
    }
    await s.client.close();
  }

  private async sweepIdle() {
    const now = Date.now();
    for (const [chatId, s] of this.sessions) {
      // --- Runtime Health Monitor ---
      // Detect subprocess that silently died (pid no longer valid) but
      // exit event hasn't fired yet (possible on Windows when parent shell
      // exits but Node doesn't see the signal).
      const clientPid = "pid" in s.client ? (s.client as { pid?: number }).pid : undefined;
      if (!s.client.isClosed && clientPid !== undefined) {
        try {
          // process.kill(pid, 0) throws if pid doesn't exist — non-destructive probe
          process.kill(clientPid, 0);
        } catch {
          // Process is gone but client didn't fire exit event
          console.error(`[health] chat ${chatId}: ACP subprocess (pid=${clientPid}) is dead, forcing cleanup`);
          logEvent("session_end", { reason: "health_monitor_dead_process" }, { chatId, userId: s.userId });
          this.sessions.delete(chatId);
          // Preserve context: archive what streamed, or carry the prior archive
          // forward (it was already deleted from disk when this session started).
          if (s.history.length > 0 || s.priorArchive) {
            await this.archiveOnClose(s, "health_monitor");
          }
          s.client.close().catch(() => {});
          if (this.onUnexpectedExit) {
            this.onUnexpectedExit(s, null).catch((e) =>
              console.error(`[health ${chatId}] onUnexpectedExit failed:`, e),
            );
          }
          continue; // skip idle check for this session
        }
      }

      // --- Idle timeout sweep ---
      if (now - s.lastUsed > config.sessionIdleMs) {
        console.log(`[session] dropping idle chat ${chatId}`);
        this.sessions.delete(chatId);
        // Archive session state before closing (summary + trivial carry-forward)
        if (s.history.length > 0 || s.priorArchive) {
          await this.archiveOnClose(s, "idle");
        }
        if (this.onBeforeClose) {
          try { await this.onBeforeClose(s); } catch (e) {
            console.error(`[session ${chatId}] onBeforeClose failed:`, e);
          }
        }
        s.client.close().catch(() => {});
      }
    }
  }

  async shutdown() {
    clearInterval(this.sweeper);
    const all = Array.from(this.sessions.values());
    this.sessions.clear();
    console.log(`[session] shutdown: flushing ${all.length} session(s)`);
    // Archive all sessions before closing (summary + trivial carry-forward)
    for (const s of all) {
      if (!s.client.isClosed && (s.history.length > 0 || s.priorArchive)) {
        await this.archiveOnClose(s, "restart");
      }
    }
    if (this.onBeforeClose) {
      for (const s of all) {
        if (s.client.isClosed) {
          console.log(`[session] shutdown: skipping already-closed chat ${s.chatId}`);
          continue;
        }
        console.log(`[session] shutdown: running onBeforeClose for chat ${s.chatId} (history=${s.history.length})`);
        try { await this.onBeforeClose(s); } catch (e) {
          console.error(`[session ${s.chatId}] onBeforeClose failed:`, e);
        }
      }
    }
    await Promise.all(all.map((s) => s.client.isClosed ? Promise.resolve() : s.client.close()));
    console.log(`[session] shutdown: done`);
  }
}

