/**
 * run-prompt.ts — Core agent prompt execution logic.
 * Extracted from index.ts (P3 split).
 */
import path from "node:path";
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { Bot, Context, InlineKeyboard } from "grammy";
import { config } from "./config.js";
import { SessionManager, ChatSession, isRelayDelegatePlaceholderGoal } from "./sessionManager.js";
import {
  transform as transformReplyTokens,
} from "./observerTransformer.js";
import * as goalStore from "./goalStore.js";
import * as usageStore from "./usageStore.js";
import { logEvent } from "./event-log.js";
import { STICKER_MAP } from "./stickerMap.js";
import { sendRelay, sendRelayFile, sendRelayDelegate, sendRelayResult, DELEGATE_PREFIX } from "./relay.js";
import type { DelegatePayload, ResultPayload } from "./relay.js";
import { isEmbedModelReady, embedText, cosineSim } from "./embed-router.js";
import { detectSkillDir } from "./memory.js";
import { isLocalSpecialist, dispatchToSpecialist, dispatchParallel, startProxy, endProxy, promptProxy, getProxyStats, buildProxySummary } from "./specialist.js";
import type { ParallelTask } from "./specialist.js";
import { appendRoutingLog } from "./routing-log.js";
import { verifySpecialistOutput, buildRetryPrompt } from "./verifier.js";
import { synthesizeDualPath, buildFusionContext } from "./self-fusion.js";
import { saveArtifact } from "./artifact.js";
import { isDuplicateResult } from "./reply-dedup.js";
import { petState, petEmit } from "./pet-server.js";
import { registerTask, completeTask } from "./status-store.js";
import {
  maskCodeRegions, buildAskKeyboard, sendFilesByPaths,
  splitForTelegram, renderReply, askRegistry, TG_MAX,
  type ScheduleParsers,
} from "./telegram-ui.js";
import {
  extractMemoryTokensFromProxy, stripMemoryTokens, saveDelegationContext,
  loadDelegationContext, notifyRelayOwner, getRelayLoopGuard, upsertRelayTask,
  addRelayTaskOutput,
} from "./commands/relay.js";
import { scheduleParsers, parseDuration, parseAbsoluteTime } from "./commands/schedule.js";
import { estimateTokens, pct } from "./commands/misc.js";
import { formatRelative } from "./utils.js";
import { autoWikilink } from "./wiki-retrieval.js";
import { evaluateForAutoSave, recordAutoSaveCandidate } from "./query-auto-save.js";
import { parseRecurrence, computeNextRunAt, formatRecurrence } from "./recurrence.js";
import { ScheduleStore } from "./schedule-store.js";
import { Scheduler } from "./scheduler.js";
import type { ContinuationContext } from "./types.js";
import { tryEditRichMessageDraft, trySendRichMessage } from "./telegram-rich-renderer.js";
import { quotaHint } from "./provider/quota-error.js";

// ─── Types ───────────────────────────────────────────────────────────────────

/** Same shape as ContinuationContext; re-aliased so the runPrompt body
 * can distinguish "plan scheduled for next turn" from "we're currently
 * running one" at the type level. */
type ContinuationPlan = ContinuationContext;

export type RunPromptMode =
  | { kind: "user"; replyHeader?: string }
  | { kind: "continuation"; context: ContinuationContext }
  | { kind: "meta"; silent?: boolean }
  | { kind: "relay"; replyTo: string };

// ─── Sticker auto-selection ──────────────────────────────────────────────────

const EMOTION_REPRS: Record<string, string> = {
  hello: "打招呼 你好 嗨 早安 晚安 greeting",
  happy: "開心 太好了 成功 完成了 恭喜 great",
  thanks: "謝謝 感謝 thank you 不客氣",
  sorry: "抱歉 對不起 不好意思 sorry",
  agree: "同意 沒問題 好的 了解 ok sure",
  good: "做得好 讚 很棒 nice well done",
  clap: "恭喜 太厲害了 完美 bravo",
  love: "喜歡 愛 太棒了 超讚",
  sad: "可惜 遺憾 不幸 unfortunately",
  shock: "驚訝 天啊 沒想到 wow unexpected",
  ok: "收到 了解 知道了 acknowledged",
};
const STICKER_AUTO_THRESHOLD = 0.65;
const STICKER_AUTO_MAX_REPLY_LEN = 150;
let emotionVectors: Map<string, Float32Array> | null = null;

export async function autoSelectSticker(reply: string): Promise<string | null> {
  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
  if (!emotionVectors) {
    emotionVectors = new Map();
    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
      const vec = await embedText(repr);
      if (vec) emotionVectors.set(emotion, vec);
    }
  }
  const queryVec = await embedText(reply);
  if (!queryVec) return null;
  let best = "";
  let bestScore = 0;
  for (const [emotion, vec] of emotionVectors) {
    const score = cosineSim(queryVec, vec);
    if (score > bestScore) { bestScore = score; best = emotion; }
  }
  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
}

// ─── Continuation timer ──────────────────────────────────────────────────────

const GOAL_CONTINUATION_DELAY_MS = 500;
const pendingContinuations = new Map<number, NodeJS.Timeout>();

export function cancelPendingContinuation(chatId: number): void {
  const h = pendingContinuations.get(chatId);
  if (h) {
    clearTimeout(h);
    pendingContinuations.delete(chatId);
  }
}

// ─── Deps interface — mutable state that lives in index.ts ───────────────────

export interface RunPromptDeps {
  bot: Bot;

