302	// ─── runPrompt ────────────────────────────────────────────────────────────────
303	
304	export async function runPrompt(
305	  ctx: Context,
306	  session: ChatSession,
307	  text: string,
308	  mode: RunPromptMode = { kind: "user" },
309	) {
310	  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
311	    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();
312	
313	  const continuationContext: ContinuationContext | undefined =
314	    mode.kind === "continuation" ? mode.context : undefined;
315	  const isMeta = mode.kind === "meta";
316	  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
317	  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
318	  const isRelay = mode.kind === "relay";
319	  // Optional header prepended to the visible reply (and shown in the "Thinking…"
320	  // placeholder). Used e.g. by ASK button clicks to record "我選擇了：X" in the
321	  // reply itself, so the original button message isn't rewritten and no extra
322	  // message is sent. Render-only — NOT added to agent history/memory.
323	  const replyHeader = mode.kind === "user" ? mode.replyHeader : undefined;
324	  const chatId = ctx.chat!.id;
325	
326	  // Guard against concurrent prompts on the same ACP session.
327	  if (session.inflight) {
328	    if (relayReplyTo) {
329	      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
330	        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
331	      );
332	      notifyRelayOwner(
333	        bot,
334	        config.allowedUserIds[0] ?? 0,
335	        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
336	        `busy notice for ${relayReplyTo}`,
337	      );
338	      return;
339	    }
340	    if (isMeta) {
341	      console.log(`[chat ${chatId}] meta prompt queued (session inflight)`);
342	      session._pendingMetaQueue.push({ ctx: ctx as unknown as any, prompt: text, opts: mode as any });
343	      return;
344	    }
345	    await ctx.reply(
346	      "⏳ 上一個回合還在進行中。請等它結束，或先用 /cancel 取消。",
347	    );
348	    return;
349	  }
350	  session.inflight = true;
351	  sessions.resetTurn(session);
352	  petState("thinking");
353	
354	  let continuationPlan: ContinuationPlan | null = null;
355	  let continueTokenFired = false;
356	  let pendingRestartReason: string | null = null;
357	
358	  if (!continuationContext) {
359	    session.history.push({ role: "user", text, timestamp: Date.now() });
360	  }
361	  session.charsIn += text.length;
362	
363	  // Context Budget Warning: inject once when context reaches 70%
