#!/usr/bin/env node
/**
 * impact-gate — 閘門 A/B 最小版（Claude-only）。
 *
 * PreToolUse hook：每 session 每檔首次 Edit/Write 阻擋一次（exit 2），
 * 要求 model 先輸出 🟠 收到/打算（session 首次）+ ⚠️ 因果鏈分析，重試即放行。
 * 誠實邊界：只強制「擋一次逼輸出」，分析深度仍是文字層自律。
 *
 * 範圍：只閘專案內檔案；.claude/ 內與專案外路徑直接放行。
 * 狀態：os.tmpdir()/impact-gate/<session_id>/，session 結束自然作廢。
 * 失敗策略：任何解析錯誤 fail-open（exit 0），不擋正常工作。
 */
import { createHash } from "node:crypto";
import { existsSync, mkdirSync, writeFileSync } from "node:fs";
import { join, resolve } from "node:path";
import { tmpdir } from "node:os";

const chunks = [];
process.stdin.on("data", (c) => chunks.push(c));
process.stdin.on("end", () => {
  try {
    main(JSON.parse(Buffer.concat(chunks).toString("utf8")));
  } catch {
    process.exit(0); // fail-open
  }
});

function main(input) {
  const filePath =
    input?.tool_input?.file_path ?? input?.tool_input?.notebook_path ?? "";
  const sessionId = String(input?.session_id ?? "unknown").replace(/[^\w-]/g, "_");
  if (!filePath) process.exit(0);

  const norm = resolve(filePath).replace(/\\/g, "/").toLowerCase();
  const root = resolve(process.cwd()).replace(/\\/g, "/").toLowerCase() + "/";

  // 只閘專案內檔案；.claude/（設定、hook 自身、todo 等）不閘
  if (!norm.startsWith(root) || norm.includes("/.claude/")) process.exit(0);

  const stateDir = join(tmpdir(), "impact-gate", sessionId);
  mkdirSync(stateDir, { recursive: true });

  const sessionMarker = join(stateDir, "_session");
  const fileMarker = join(stateDir, createHash("sha1").update(norm).digest("hex"));

  if (existsSync(fileMarker)) process.exit(0); // 此檔已放行過

  const firstInSession = !existsSync(sessionMarker);
  // 先蓋章再阻擋：下次重試同一修改即放行
  writeFileSync(sessionMarker, "");
  writeFileSync(fileMarker, "");

  const lines = [
    `[impact-gate] 首次修改 ${filePath} — 先輸出以下分析，然後重試同一修改（重試即放行）：`,
  ];
  if (firstInSession) {
    lines.push("🟠 收到：[用戶意圖]", "🟠 打算：[一句話]");
  }
  lines.push(
    "⚠️ [因果鏈分析] 修改 {檔案}:{函式}",
    "├─ 根因：為什麼要改",
    "├─ 呼叫者：grep N 個逐一分析（檔:行 — 影響 — 需連動是/否）；呼叫者=0 → 停，先找真正執行路徑",
    "├─ 隱性風險：快取失效/時序變化/語意漂移",
    "└─ 決策：連動清單或不需要的理由",
  );
  process.stderr.write(lines.join("\n"));
  process.exit(2);
}
